def truncate_memory(memory, max_tokens=4000):
    tokens = len(str(memory).split())
    if tokens > max_tokens:
        # Keep last N turns
        history = memory['history'][-4:]  # Last 4 exchanges
        memory = {'history': history}
    return memory

