async def process_audio(self, audio_bytes):
    text = stt.transcribe(audio_bytes)['text']

    # Vex verification
    if not vex.verify('memory_size', {'tokens': len(str(self.memory).split())}):
        self.memory = truncate_memory(self.memory)

    response = await agent.run(text, memory=self.memory)
    self.memory['history'].append({'user': text, 'assistant': response})
    return piper_tts.synthesize(response)

from pydantic import BaseModel, validator

class DBQueryTool(BaseModel):
    sql: str

    @validator('sql')
    def validate_sql(cls, v):
        forbidden = ['DROP', 'DELETE', 'UPDATE']
        if any(word in v.upper() for word in forbidden):
            raise ValueError('Dangerous SQL detected')
        return v

# Register validated tool
tool = beeai.Tool('query_db')
tool.schema = DBQueryTool.model_json_schema()
agent.add_tool(tool)

# Vex double-checks
async def safe_tool_call(tool_name, params):
    verdict = vex.verify('tool_safety', {'tool': tool_name, 'params': params})
    if not verdict:
        raise ValueError('Tool call blocked by Vex')
    return await agent.execute_tool(tool_name, params)

