from vex import VexClient
from beeai import Agent

vex = VexClient(api_key='your-vex-key', project='voice-agent')

@vex.listener('beeai_voice_agent')
def handle_beeai_events(event):
    if event.type == 'agent_start':
        vex.set_context('session_id', event.session_id)
        vex.set_verification('response_appropriateness', threshold=0.9)

    elif event.type == 'memory_update':
        tokens = len(event.data['content'].split())
        vex.verify('memory_growth', {'tokens': tokens, 'max': 4000})

    elif event.type == 'tool_call':
        vex.verify('tool_safety', {
            'tool': event.data['name'],
            'params': event.data['parameters']
        })

    elif event.type == 'agent_complete':
        vex.verify('coherence', {'response': event.data['output']})

# Attach to agent
agent = Agent()
agent.add_event_listener(vex_listener=handle_beeai_events)
vex.deploy_pipeline('beeai-voice-v1')

from vex.llm import LLMVerifier

coherence_checker = LLMVerifier(
    provider='granite',
    prompt_template="""Verify if this response maintains conversation coherence:

History: {history}
User: {user_input}
Response: {response}

Is the response coherent and contextually appropriate? Return JSON: {{"coherent": true/false, "reason": "..."}}"""
)

def check_coherence(history, user_input, response):
    verdict = coherence_checker.verify({
        'history': history[-3:],
        'user_input': user_input,
        'response': response
    })

    if not verdict.get('coherent', False):
        vex.record_violation('coherence_fail', verdict['reason'])
        return False
    return True

# Pipeline integration
if check_coherence(memory['history'], text, agent_response):
    memory['history'].append({'user': text, 'assistant': agent_response})
